## Security Review of app.js

I've analyzed the application for common vulnerabilities. Here's my comprehensive security assessment:

### **Overall Risk Level: MEDIUM**

The application is relatively simple, but has several security gaps that need to be addressed. Below are the findings organized by OWASP Top 10 categories:

---

## **Critical & High-Risk Issues**

### 1. **A01:2021 – Broken Access Control / Missing Authentication**
**Risk: HIGH**

**Issue:** Both `/health` and `/users` endpoints lack any authentication or authorization controls. Sensitive user data is exposed without verification.

**Current Code:**
```javascript
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Recommendation:**
```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

// Middleware for authentication
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// Protected endpoint with authentication
app.get('/users', authenticateToken, (req, res) => {
  // Optionally add role-based access control
  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Insufficient permissions' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

---

### 2. **A03:2021 – Injection**
**Risk: MEDIUM (Current)**

**Issue:** While the current code doesn't have obvious injection vulnerabilities, if this app scales to accept user input (especially in query parameters or request bodies), it's vulnerable without proper validation.

**Potential Vulnerability Example:**
```javascript
// UNSAFE - DO NOT USE
app.get('/search', (req, res) => {
  const query = req.query.name; // Unvalidated input
  // If this were used in a database query without parameterization:
  // db.query(`SELECT * FROM users WHERE name = '${query}'`); // SQL INJECTION!
  res.json({});
});
```

**Recommendation:**
```javascript
const { body, query, validationResult } = require('express-validator');

// Input validation middleware
app.get('/search', 
  query('name')
    .trim()
    .isLength({ min: 1, max: 100 })
    .escape()
    .matches(/^[a-zA-Z0-9\s\-']+$/) // Whitelist allowed characters
    .withMessage('Invalid search query'),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const query = req.query.name;
    // Use parameterized queries if querying database
    // db.query('SELECT * FROM users WHERE name = ?', [query]);
    res.json({});
  }
);
```

---

### 3. **A05:2021 – Security Misconfiguration**
**Risk: HIGH**

**Issues:**
- No CORS configuration (open to all origins)
- No security headers (missing helmet.js)
- No rate limiting
- No input parsing limits

**Recommendation:**
```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// Security headers
app.use(helmet());

// CORS configuration (restrict to trusted origins)
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://yourdomain.com'],
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization']
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later'
});
app.use(limiter);

// Parse JSON with size limits
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ limit: '10mb', extended: true }));

// Your routes here
```

---

### 4. **A07:2021 – Identification and Authentication Failures**
**Risk: HIGH**

**Issue:** No session management, password policies, or token expiration mechanisms.

**Recommendation:** Implement proper authentication:
```javascript
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');

// Login endpoint with proper authentication
app.post('/login', 
  body('email').isEmail().normalizeEmail(),
  body('password').isLength({ min: 8 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // In production: fetch from database and compare hashed password
    const user = await findUserByEmail(req.body.email);
    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const passwordMatch = await bcrypt.compare(req.body.password, user.passwordHash);
    if (!passwordMatch) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Generate JWT with expiration
    const token = jwt.sign(
      { id: user.id, email: user.email, role: user.role },
      process.env.JWT_SECRET,
      { expiresIn: '1h' } // Token expires in 1 hour
    );

    res.json({ 
      token,
      expiresIn: 3600
    });
  }
);
```

