### 1. **A01:2021 – Broken Access Control / Missing Authentication**
**Risk: HIGH**

**Issue:** Both `/health` and `/users` endpoints lack any authentication or authorization controls. Sensitive user data is exposed without verification.

**Current Code:**
```javascript
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Recommendation:**
```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

// Middleware for authentication
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// Protected endpoint with authentication
app.get('/users', authenticateToken, (req, res) => {
  // Optionally add role-based access control
  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Insufficient permissions' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

